const t1 = $('PG: Redemption Totals').item.json;
const t2 = $('PG: Return Rate').item.json;

function parseRes(x) {
  let r = x?.result;
  if (typeof r === 'string') { try { r = JSON.parse(r); } catch(e) { r = []; } }
  return Array.isArray(r) ? r : [];
}

const totalsArr = parseRes(t1);
const returnsArr = parseRes(t2);
const totals = totalsArr[0]?.data || {};
const returns = returnsArr[0] || {};

const d = new Date().toISOString().slice(0,10);

if ((totals.codes_created || 0) === 0) {
  const text = '\ud83d\udcc8 <b>Winback Post-Campaign Report</b>\n<i>' + d + '</i>\n\n\u0417\u0430 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0435 30 \u0434\u043d\u0435\u0439 \u043d\u0435 \u0441\u043e\u0437\u0434\u0430\u043d\u043e \u043d\u0438 \u043e\u0434\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u043c\u043e\u043a\u043e\u0434\u0430 \u0441 \u043f\u0440\u0435\u0444\u0438\u043a\u0441\u043e\u043c WB \u2014 \u043d\u0435\u0447\u0435\u0433\u043e \u0430\u043d\u0430\u043b\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u0442\u044c.';
  return [{json: {text, skip_if_empty: true}}];
}

const created = totals.codes_created || 0;
const redeemed = totals.codes_redeemed || 0;
const conv = totals.conversion_pct || 0;
const users = totals.unique_redeemers || 0;
const discountGiven = totals.discount_given_eur || 0;
const redemptionGmv = totals.redemption_gmv_eur || 0;

const usersWithPromo = returns.users_with_promo || 0;
const usersReturned = returns.users_returned || 0;
const gmvAfter = returns.total_gmv_after || 0;
const returnRate = usersWithPromo > 0 ? Math.round(100 * usersReturned / usersWithPromo) : 0;

const roi = discountGiven > 0 ? (gmvAfter / discountGiven).toFixed(1) : 'N/A';

const text = '\ud83d\udcc8 <b>Winback Post-Campaign Report</b>\n<i>' + d + ' | \u043e\u043a\u043d\u043e: 30 \u0434\u043d\u0435\u0439</i>\n\n' +
  '<b>\u041f\u0440\u043e\u043c\u043e\u043a\u043e\u0434\u044b (WB*):</b>\n' +
  '\u2022 \u0421\u043e\u0437\u0434\u0430\u043d\u043e: ' + created + '\n' +
  '\u2022 \u0410\u043a\u0442\u0438\u0432\u0438\u0440\u043e\u0432\u0430\u043d\u043e: ' + redeemed + ' (' + conv + '%)\n' +
  '\u2022 \u0423\u043d\u0438\u043a\u0430\u043b\u044c\u043d\u044b\u0445 \u044e\u0437\u0435\u0440\u043e\u0432: ' + users + '\n' +
  '\u2022 \u0412\u044b\u0434\u0430\u043d\u043e \u0441\u043a\u0438\u0434\u043a\u0438: \u20ac' + discountGiven + '\n' +
  '\u2022 GMV \u043f\u043e \u043f\u0440\u043e\u043c\u043e\u043a\u043e\u0434\u0443: \u20ac' + redemptionGmv + '\n\n' +
  '<b>\u0412\u043e\u0437\u0432\u0440\u0430\u0442 \u0432 \u0440\u0438\u0442\u043c:</b>\n' +
  '\u2022 \u0412\u0435\u0440\u043d\u0443\u043b\u043e\u0441\u044c: ' + usersReturned + ' \u0438\u0437 ' + usersWithPromo + ' (' + returnRate + '%)\n' +
  '\u2022 GMV \u043f\u043e\u0441\u043b\u0435 \u0432\u044b\u0434\u0430\u0447\u0438 \u043f\u0440\u043e\u043c\u043e\u043a\u043e\u0434\u0430: \u20ac' + gmvAfter + '\n' +
  '\u2022 ROI (GMV/\u0441\u043a\u0438\u0434\u043a\u0430): \u00d7' + roi + '\n\n' +
  (returnRate >= 30 ? '\u2705 \u041a\u0430\u043c\u043f\u0430\u043d\u0438\u044f \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u2014 \u043f\u0440\u043e\u0434\u043e\u043b\u0436\u0430\u0442\u044c.' : '\u26a0\ufe0f \u041e\u0442\u043a\u043b\u0438\u043a \u043d\u0438\u0437\u043a\u0438\u0439 \u2014 \u0440\u0430\u0437\u043e\u0431\u0440\u0430\u0442\u044c\u0441\u044f \u0441 \u043a\u0430\u043d\u0430\u043b\u043e\u043c/\u043e\u0444\u0444\u0435\u0440\u043e\u043c.');

return [{json: {text}}];
